import style from "./index.module.scss"
import template from "./index.html"
import {Select, Nav} from "../types"
import theme from "../utils/theme"

export default class App extends HTMLElement {
  nav: Nav
  navBtn: HTMLElement
  homePage: HTMLElement
  contactPage: HTMLElement
  mortgagePage: HTMLElement
  select: Select
  appEle: HTMLElement
  constructor() {
    super();
  }
  
  connectedCallback() {
    this.classList.add("hydrated")
    const sheet = document.createElement("style")
    sheet.innerHTML = style 
    this.innerHTML = template
    this.appendChild(sheet)
    this.willLoad()
    this.render()
    theme.setElement(this.querySelector("#app"))
  }
  disconnectedCallback() {
    this.nav && (this.nav.open = false)
    this.navBtn?.removeEventListener("click", this.handleNavBtnClick)
    this.navBtn?.removeEventListener("keydown", this.handleNavKeydown)
    this.expandBtn?.removeEventListener("click", this.handleNavExpandBtnOpenClose)
  }
  handleSwitchPage = (value) => {
    if (value === "contact") {
      window.location.hash = "contact"
    } else if (value === "home") {
      window.location.hash = "home"
    } else if (value === "mortgage") {
      window.location.hash = "mortgage"
    } else if (value === "ui-demo-one") {
      window.location.hash = "demo-one"
    } else if (value === "ui-demo-two") {
      window.location.hash = "demo-two"
    }
  }
  handleNavBtnClick = e => {
    if (e.clientX === 0 || e.clientY === 0) return
    this.handleNavOpenClose()
  }
  handleNavKeydown = e => {
    if (["Enter", " "].includes(e.key)) this.handleNavOpenClose({focus: true})
  }
  willLoad = () => {
    const slot = this.querySelector("#slot")
    if (!slot) return
    this.select = this.querySelector(".me-select") as Select
    const hash = window.location.hash.slice(1)
    if (["home", "contact", "mortgage"].includes(hash)) {
      setTimeout(() => {
        this.select.setAttribute("value", hash)
      })
    }
    this.select.addEventListener("click", e => {
      const name = e.target.getAttribute("name")
      if (!name) return 
      this.handleSwitchPage(name)
    })
    
    this.navBtn = this.querySelector("#open-navigation-button") as HTMLElement
    this.navBtn?.addEventListener("click", this.handleNavBtnClick)
    this.navBtn?.addEventListener("keydown", this.handleNavKeydown)
    this.nav = this.querySelector("huanlin-app huanlin-nav") as Nav
    this.expandBtn = this.nav.querySelector("#expand-button")
    this.expandBtn?.addEventListener("click", this.handleNavExpandBtnOpenClose)
    this.nav.addEventListener("keydown", e => {
      if (e.key === "Escape") {
        this.navBtn.focus()
      }
    })
    this.nav.addEventListener("click", this.handleActivePage)
    this.nav.addEventListener("keydown", e => {
      if ([" ", "Enter"].includes(e.key)) {
        this.handleActivePage(e)
      }
    })
  }
  handleNavExpandBtnOpenClose = e => {
    if (this.nav.collapse) {
      this.nav.collapse = false
    } else {
      this.nav.collapse = true
    }
  }

  handleActivePage = e => {
    const ele = e.target.closest("huanlin-nav-item") as HTMLElement
    const isNavItem = ele?.tagName === "HUANLIN-NAV-ITEM"
    if (isNavItem) {
      const name = ele?.getAttribute("name")
      this.handleSwitchPage(name)
      if (!["ui-demo-one", "ui-demo-two"].includes(ele.name)) this.select.setActiveOption(name)
    }
  }
  handleNavOpenClose = (option?) => {
    if (this.nav.open) {
      this.nav.open = false
      this.setAttribute("aria-pressed", "false")
    } else {
      this.nav.open = true
      this.setAttribute("aria-pressed", "true")
      option && option.focus && setTimeout(() => {
        this.nav.handleFocusFirstItem()
      }, 100)
    }
  }

  render = () => {
  }
}
